import {
  useAuth,
  useChangePassword,
  useListAccounts,
  useRequestPasswordReset,
  useSession
} from "@better-auth-ui/solid"
import type { BetterFetchError } from "better-auth/client"
import { Eye, EyeOff } from "lucide-solid"
import { createSignal, Show } from "solid-js"
import { toast } from "solid-sonner"
import type { ChangePasswordFieldErrors } from "@/components/auth/settings/shared/types"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardFooter } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Skeleton } from "@/components/ui/skeleton"
import { cn } from "@/lib/utils"

function ChangePasswordSkeletonInput() {
  return (
    <Skeleton>
      <Input class="invisible" />
    </Skeleton>
  )
}

export type ChangePasswordSettingsProps = {
  class?: string
  confirmPassword?: boolean
}

export function ChangePasswordSettings(
  props: ChangePasswordSettingsProps = {}
) {
  const auth = useAuth()
  const session = useSession(auth.authClient)
  const linkedAccounts = useListAccounts(auth.authClient)
  const hasCredentialAccount = () =>
    linkedAccounts.data?.some(
      (account: { providerId?: string }) => account.providerId === "credential"
    )
  const requestPasswordReset = useRequestPasswordReset(auth.authClient, {
    onSuccess: () =>
      toast.success(auth.localization.auth.passwordResetEmailSent)
  })
  const changePassword = useChangePassword(auth.authClient, {
    onError: (error: BetterFetchError) => {
      setCurrentPassword("")
      setNewPassword("")
      setConfirmPassword("")
      toast.error(error.error?.message || error.message)
    },
    onSuccess: () => {
      setCurrentPassword("")
      setNewPassword("")
      setConfirmPassword("")
      toast.success(auth.localization.settings.changePasswordSuccess)
    }
  })
  const [currentPassword, setCurrentPassword] = createSignal("")
  const [newPassword, setNewPassword] = createSignal("")
  const [confirmPassword, setConfirmPassword] = createSignal("")
  const [isNewPasswordVisible, setIsNewPasswordVisible] = createSignal(false)
  const [isConfirmPasswordVisible, setIsConfirmPasswordVisible] =
    createSignal(false)
  const [fieldErrors, setFieldErrors] = createSignal<ChangePasswordFieldErrors>(
    {}
  )

  const setPasswordFieldError = (
    field: keyof ChangePasswordFieldErrors,
    message?: string
  ) => {
    setFieldErrors((previous) => ({ ...previous, [field]: message }))
  }

  const resetPasswordFields = () => {
    setCurrentPassword("")
    setNewPassword("")
    setConfirmPassword("")
  }

  const sendResetLink = () => {
    if (!session.data) return

    requestPasswordReset.mutate({
      email: session.data.user.email
    } as Parameters<typeof requestPasswordReset.mutate>[0])
  }

  const submitChangePassword = (event: SubmitEvent) => {
    event.preventDefault()

    if (props.confirmPassword && newPassword() !== confirmPassword()) {
      resetPasswordFields()
      toast.error(auth.localization.auth.passwordsDoNotMatch)
      return
    }

    changePassword.mutate({
      currentPassword: currentPassword(),
      newPassword: newPassword(),
      revokeOtherSessions: true
    } as Parameters<typeof changePassword.mutate>[0])
  }

  const isPasswordPending = () =>
    changePassword.isPending || requestPasswordReset.isPending

  if (!linkedAccounts.isPending && !hasCredentialAccount()) {
    return (
      <div class={cn(props.class)}>
        <h2 class="mb-3 text-sm font-semibold">
          {auth.localization.settings.changePassword}
        </h2>

        <Card>
          <CardContent class="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
            <div>
              <p class="font-medium text-sm leading-tight">
                {auth.localization.settings.setPassword}
              </p>
              <p class="mt-0.5 text-muted-foreground text-xs">
                {auth.localization.settings.setPasswordDescription}
              </p>
            </div>

            <Button
              disabled={requestPasswordReset.isPending || !session.data}
              onClick={sendResetLink}
              size="sm"
              type="button"
            >
              {requestPasswordReset.isPending
                ? `${auth.localization.auth.sendResetLink}…`
                : auth.localization.auth.sendResetLink}
            </Button>
          </CardContent>
        </Card>
      </div>
    )
  }

  return (
    <div class={cn(props.class)}>
      <h2 class="mb-3 text-sm font-semibold">
        {auth.localization.settings.changePassword}
      </h2>

      <form onSubmit={submitChangePassword}>
        <Card>
          <CardContent class="flex flex-col gap-6">
            <div class="grid gap-2">
              <Label for="currentPassword">
                {auth.localization.settings.currentPassword}
              </Label>
              <Show
                fallback={<ChangePasswordSkeletonInput />}
                when={session.data && !linkedAccounts.isPending}
              >
                <Input
                  aria-invalid={!!fieldErrors().currentPassword}
                  autocomplete="current-password"
                  disabled={isPasswordPending()}
                  id="currentPassword"
                  name="currentPassword"
                  onInput={(event) => {
                    setCurrentPassword(event.currentTarget.value)
                    setPasswordFieldError("currentPassword")
                  }}
                  onInvalid={(event) => {
                    event.preventDefault()
                    setPasswordFieldError(
                      "currentPassword",
                      event.currentTarget.validationMessage
                    )
                  }}
                  placeholder={
                    auth.localization.settings.currentPasswordPlaceholder
                  }
                  required
                  type="password"
                  value={currentPassword()}
                />
              </Show>
              <Show when={fieldErrors().currentPassword}>
                {(message) => (
                  <p class="text-destructive text-sm" role="alert">
                    {message()}
                  </p>
                )}
              </Show>
            </div>

            <div class="grid gap-2">
              <Label for="newPassword">
                {auth.localization.auth.newPassword}
              </Label>
              <Show
                fallback={<ChangePasswordSkeletonInput />}
                when={session.data && !linkedAccounts.isPending}
              >
                <div class="relative">
                  <Input
                    aria-invalid={!!fieldErrors().newPassword}
                    autocomplete="new-password"
                    class="pr-12"
                    disabled={isPasswordPending()}
                    id="newPassword"
                    maxLength={auth.emailAndPassword.maxPasswordLength}
                    minLength={auth.emailAndPassword.minPasswordLength}
                    name="newPassword"
                    onInput={(event) => {
                      setNewPassword(event.currentTarget.value)
                      setPasswordFieldError("newPassword")
                    }}
                    onInvalid={(event) => {
                      event.preventDefault()
                      setPasswordFieldError(
                        "newPassword",
                        event.currentTarget.validationMessage
                      )
                    }}
                    placeholder={auth.localization.auth.newPasswordPlaceholder}
                    required
                    type={isNewPasswordVisible() ? "text" : "password"}
                    value={newPassword()}
                  />
                  <Button
                    aria-label={
                      isNewPasswordVisible()
                        ? auth.localization.auth.hidePassword
                        : auth.localization.auth.showPassword
                    }
                    class="absolute right-1 top-1/2 -translate-y-1/2"
                    disabled={isPasswordPending()}
                    onClick={() =>
                      setIsNewPasswordVisible((visible) => !visible)
                    }
                    size="icon-sm"
                    title={
                      isNewPasswordVisible()
                        ? auth.localization.auth.hidePassword
                        : auth.localization.auth.showPassword
                    }
                    type="button"
                    variant="ghost"
                  >
                    {isNewPasswordVisible() ? (
                      <EyeOff aria-hidden class="size-4" />
                    ) : (
                      <Eye aria-hidden class="size-4" />
                    )}
                  </Button>
                </div>
              </Show>
              <Show when={fieldErrors().newPassword}>
                {(message) => (
                  <p class="text-destructive text-sm" role="alert">
                    {message()}
                  </p>
                )}
              </Show>
            </div>

            <Show when={props.confirmPassword}>
              <div class="grid gap-2">
                <Label for="confirmPassword">
                  {auth.localization.auth.confirmPassword}
                </Label>
                <Show
                  fallback={<ChangePasswordSkeletonInput />}
                  when={session.data && !linkedAccounts.isPending}
                >
                  <div class="relative">
                    <Input
                      aria-invalid={!!fieldErrors().confirmPassword}
                      autocomplete="new-password"
                      class="pr-12"
                      disabled={isPasswordPending()}
                      id="confirmPassword"
                      maxLength={auth.emailAndPassword.maxPasswordLength}
                      minLength={auth.emailAndPassword.minPasswordLength}
                      name="confirmPassword"
                      onInput={(event) => {
                        setConfirmPassword(event.currentTarget.value)
                        setPasswordFieldError("confirmPassword")
                      }}
                      onInvalid={(event) => {
                        event.preventDefault()
                        setPasswordFieldError(
                          "confirmPassword",
                          event.currentTarget.validationMessage
                        )
                      }}
                      placeholder={
                        auth.localization.auth.confirmPasswordPlaceholder
                      }
                      required
                      type={isConfirmPasswordVisible() ? "text" : "password"}
                      value={confirmPassword()}
                    />
                    <Button
                      aria-label={
                        isConfirmPasswordVisible()
                          ? auth.localization.auth.hidePassword
                          : auth.localization.auth.showPassword
                      }
                      class="absolute right-1 top-1/2 -translate-y-1/2"
                      disabled={isPasswordPending()}
                      onClick={() =>
                        setIsConfirmPasswordVisible((visible) => !visible)
                      }
                      size="icon-sm"
                      title={
                        isConfirmPasswordVisible()
                          ? auth.localization.auth.hidePassword
                          : auth.localization.auth.showPassword
                      }
                      type="button"
                      variant="ghost"
                    >
                      {isConfirmPasswordVisible() ? (
                        <EyeOff aria-hidden class="size-4" />
                      ) : (
                        <Eye aria-hidden class="size-4" />
                      )}
                    </Button>
                  </div>
                </Show>
                <Show when={fieldErrors().confirmPassword}>
                  {(message) => (
                    <p class="text-destructive text-sm" role="alert">
                      {message()}
                    </p>
                  )}
                </Show>
              </div>
            </Show>
          </CardContent>

          <CardFooter>
            <Button
              disabled={isPasswordPending() || !session.data}
              size="sm"
              type="submit"
            >
              {changePassword.isPending
                ? `${auth.localization.settings.updatePassword}…`
                : auth.localization.settings.updatePassword}
            </Button>
          </CardFooter>
        </Card>
      </form>
    </div>
  )
}

export function hasAuthPlugin(plugins: { id: string }[], id: string) {
  return plugins.some((plugin) => plugin.id === id)
}

export const resolveUserLabel = (name?: string | null, email?: string | null) =>
  name?.trim() || email?.trim() || "Signed in user"

export const resolveUserInitials = (
  name?: string | null,
  email?: string | null
) => resolveUserLabel(name, email).slice(0, 2).toUpperCase()

export function timeAgo(date: Date | string) {
  const createdAt = date instanceof Date ? date : new Date(date)
  const seconds = Math.floor((Date.now() - createdAt.getTime()) / 1000)
  const relativeTimeFormat = new Intl.RelativeTimeFormat(undefined, {
    numeric: "auto"
  })

  const units: [Intl.RelativeTimeFormatUnit, number][] = [
    ["year", 31_536_000],
    ["month", 2_592_000],
    ["week", 604_800],
    ["day", 86_400],
    ["hour", 3_600],
    ["minute", 60],
    ["second", 1]
  ]

  for (const [unit, threshold] of units) {
    if (seconds >= threshold) {
      return relativeTimeFormat.format(-Math.floor(seconds / threshold), unit)
    }
  }

  return relativeTimeFormat.format(0, "second")
}

import type { getProviderName, SettingsView } from "@better-auth-ui/core"
import type { ApiKeyAuthClient } from "@better-auth-ui/core/plugins/api-key"
import type { deleteUserLocalization } from "@better-auth-ui/core/plugins/delete-user"
import type { MultiSessionAuthClient } from "@better-auth-ui/core/plugins/multi-session"
import type { ListApiKeysData } from "@better-auth-ui/solid/plugins/api-key"
import type { ListDeviceSessionsData } from "@better-auth-ui/solid/plugins/multi-session"
import type { Component } from "solid-js"

export type SettingsPanel = {
  component: Component
  title: string
}

export type SettingsRouteResolution = SettingsPanel | { redirectTo: string }

export type SecurityCardsPlugin = {
  id: string
  securityCards?: Component[]
}

export type OrganizationCardsPlugin = {
  id: string
  organizationCards?: Component[]
}

export type ChangePasswordFieldErrors = {
  confirmPassword?: string
  currentPassword?: string
  newPassword?: string
}

export type LinkedAccount = {
  accountId?: string
  id: string
  providerId: string
}

export type LinkedProvider = Parameters<typeof getProviderName>[0]

export type DeviceSession = NonNullable<
  ListDeviceSessionsData<MultiSessionAuthClient>
>[number]

export type ListedApiKey = NonNullable<
  ListApiKeysData<ApiKeyAuthClient>
>["apiKeys"][number]

export type ListedPasskey = {
  id: string
  name?: string | null
  createdAt: Date | string
}

export type AccountInfoResponse = {
  data?: {
    login?: string | null
    username?: string | null
  } | null
  user?: {
    email?: string | null
    name?: string | null
  } | null
}

export type DeleteUserPluginConfig = {
  id: string
  localization?: Partial<typeof deleteUserLocalization>
  sendDeleteAccountVerification?: boolean
}

export type SettingsPathViews = Record<string, SettingsView | string>

import { type ClassValue, clsx } from "clsx"
import { twMerge } from "tailwind-merge"

export const cn = (...inputs: ClassValue[]) => twMerge(clsx(inputs))
